#include "spi_display.h"

static TFT_eSPI _display(240, 320);

void spi_display_setup() {
    _display.init();
    _display.setRotation(1);
    _display.fillScreen(TFT_BLACK);
    _display.setTextColor(TFT_WHITE, TFT_BLACK);
    _display.setTextSize(2);
    Serial.println("[display] SPI display ready");
}

TFT_eSPI& spi_display_get() { return _display; }

void spi_display_clear(uint16_t color) { _display.fillScreen(color); }

void spi_display_text(const char* text, int x, int y, uint16_t color) {
    _display.setTextColor(color, TFT_BLACK);
    _display.setCursor(x, y);
    _display.print(text);
}

void spi_display_draw_rect(int x, int y, int w, int h, uint16_t color) {
    _display.drawRect(x, y, w, h, color);
}

void spi_display_fill_rect(int x, int y, int w, int h, uint16_t color) {
    _display.fillRect(x, y, w, h, color);
}
